const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const express = require('express');
const projectService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const project = projectService.createProject(name);
  res.status(201).json({ project });
});

router.get('/', (req, res) => {
  const projects = projectService.getAllProjects();
  res.json({ projects });
});

module.exports = router;

const { randomUUID } = require('node:crypto');
const store = require('./store');

function createProject(name) {
  const project = { id: randomUUID(), name, members: [], tasks: [] };
  store.projects.push(project);
  return project;
}

function getAllProjects() {
  return store.projects;
}

module.exports = {
  createProject,
  getAllProjects,
};

const express = require('express');
const memberService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_BODY', 'UserId and role are required');
  }
  const projectId = req.params.projectId;
  const member = memberService.addMember(projectId, userId, role);
  if (!member) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ member });
});

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const members = memberService.getMembers(projectId);
  if (!members) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.json({ members });
});

module.exports = router;

const projectStore = require('../projects/store');
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

function addMember(projectId, userId, role) {
  const project = projectStore.projects.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const member = { id: randomUUID(), userId, role };
  project.members.push(member);
  return member;
}

function getMembers(projectId) {
  const project = projectStore.projects.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  return project.members;
}

module.exports = {
  addMember,
  getMembers,
};

const express = require('express');
const taskService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const task = taskService.createTask(projectId);
  if (!task) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;
  const tasks = taskService.getTasks(projectId, status);
  if (!tasks) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  const task = taskService.updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;

const projectStore = require('../projects/store');
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

function createTask(projectId) {
  const project = projectStore.projects.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = { id: randomUUID(), status: 'todo' };
  project.tasks.push(task);
  return task;
}

function getTasks(projectId, status) {
  const project = projectStore.projects.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  if (status) {
    return project.tasks.filter(t => t.status === status);
  }
  return project.tasks;
}

function updateTaskStatus(projectId, taskId, newStatus) {
  const project = projectStore.projects.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  if (newStatus !== 'todo' && newStatus !== 'done') {
    return null;
  }
  task.status = newStatus;
  return task;
}

module.exports = {
  createTask,
  getTasks,
  updateTaskStatus,
};

const express = require('express');
const commentService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_BODY', 'Message is required');
  }
  const comment = commentService.addComment(projectId, taskId, message);
  if (!comment) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const comments = commentService.getComments(projectId, taskId);
  if (!comments) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ comments });
});

module.exports = router;

const projectStore = require('../projects/store');
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

function addComment(projectId, taskId, message) {
  const project = projectStore.projects.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  const comment = { id: randomUUID(), message };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(comment);
  return comment;
}

function getComments(projectId, taskId) {
  const project = projectStore.projects.find(p => p.id === projectId);
  if (!project) {
    return null;
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task || !task.comments) {
    return [];
  }
  return task.comments;
}

module.exports = {
  addComment,
  getComments,
};
